import React, { useRef, useState } from "react";
import "./style.css";

export default function CountersPage() {
  const [counter, setCounter] = useState(0);
  const previousCounterRef = useRef(0);
  const isPositive = counter > 0;
  const isNegative = counter < 0;
  const statusLabel = isPositive
    ? "Positive value"
    : isNegative
      ? "Negative value"
      : "Balanced value";

  const CountersPage = () => {
    const [counter, setCounter] = useState(0);
    const previousCounterRef = useRef(0);
    const isPositive = counter > 0;
    const isNegative = counter < 0;
    const statusLabel = isPositive
      ? "Positive value"
      : isNegative
        ? "Negative value"
        : "Balanced value";
  };

  const handleDecrease = () => {
    previousCounterRef.current = counter;
    setCounter((prevCounter) => prevCounter - 1);
  };

  const handleIncrease = () => {
    previousCounterRef.current = counter;
    setCounter((prevCounter) => prevCounter + 1);
  };

  const handleReset = () => {
    previousCounterRef.current = counter;
    setCounter(0);
  };

  return (
    <main className="counters-page">
      <section className="counter-panel">
        <p className="counter-kicker">Interactive Counter</p>
        <h1>Counters Page</h1>
        <p className="counter-description">
          This example uses <code>useState</code> for the current value and{" "}
          <code>useRef</code> to remember the previous one.
        </p>

        <div className="counter-summary">
          <div className="counter-summary-card">
            <span>Live status</span>
            <strong>{statusLabel}</strong>
          </div>
          <div className="counter-summary-card">
            <span>Difference</span>
            <strong>{counter - previousCounterRef.current}</strong>
          </div>
          <div className="counter-summary-card">
            <span>Hook focus</span>
            <strong>useState + useRef</strong>
          </div>
        </div>

        <div className="counter-display">
          <span>{counter}</span>
        </div>

        <p
          className={`counter-status${isPositive ? " positive" : ""}${isNegative ? " negative" : ""}`}
        >
          {statusLabel}
        </p>

        <div className="counter-history">
          <div className="counter-history-card">
            <p>Current</p>
            <strong>{counter}</strong>
          </div>
          <div className="counter-history-card">
            <p>Previous</p>
            <strong>{previousCounterRef.current}</strong>
          </div>
        </div>

        <div className="counter-actions">
          <button onClick={handleDecrease} className="counter-button secondary">
            Decrease
          </button>
          <button onClick={handleIncrease} className="counter-button primary">
            Increase
          </button>
        </div>

        <div className="counter-reset-row">
          <button onClick={handleReset} className="counter-button neutral">
            Reset
          </button>
        </div>

        <div className="counter-note">
          <h2>Quick note</h2>
          <p>
            <code>useState</code> changes the current number, while{" "}
            <code>useRef</code> keeps the previous value without forcing an
            extra render.
          </p>
        </div>
      </section>
    </main>
  );
}
